"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3849"],{12101(e,t,s){s.r(t),s.d(t,{default:()=>n});var o=s(74848),r=s(47643),i=JSON.parse('{"id":201,"en":{"title":"Process Document Generator","prompt":"You will act as a process document generator. Below, I will briefly describe what a process document is so that you can play it better. Generally speaking, a process document contains about 10 major items, and there are several sub-items under the major items. Of course, not all major items contain sub-items. The 10 major items generally include [1. Process Overview2. Objectives3. Scope of application4. Process Owner5. Definition and Terminology6. Related Process Standards (Process Interface)7. Organizational Responsibilities8. System and Operating Permissions9. Business Process Flowchart10. Process Description.] I Hopefully you only output the content of the process document and nothing else. My first process document was [Topic]","remark":"To generate an outline for documents with fixed processes, this prompt can also be applied to other types of documents. Contributed by @Junkdo."},"tags":["contribute","tool"],"website":null,"count":737,"related":[{"id":220,"title":"Travel itinerary","remark":"Based on your travel destination, budget, time, and requirements, AI can roughly plan your trip. Contributed by @suaifu."},{"id":267,"title":"Diminish resemblance","remark":"Contributed by @\u76AE\u86CB\u7626\u8089\u5468\u3002"},{"id":245,"title":"Icon designer","remark":"Transform concepts or ideas into tangible objects to concretize design concepts. Contributed by @MoonJustice."}],"metaTitle":"Process Doc Generator","metaDescription":"Need documentation? Generate standard process docs with 10 major items. Covers objectives, scope, flowcharts, and descriptions.","faq":[{"q":"Is this suitable for non-fixed processes like creative projects?","a":"Not a great fit. The prompt builds around a \\"10 top items each with sub-items\\" structure. Creative projects are more fluid and forcing them into this shape makes the document rigid. Fixed processes (invoicing, onboarding, expense reports) fit best. For creative docs, ID 214 research report or ID 187 PPT outline are more flexible."},{"q":"Does the generated process document miss key steps?","a":"Yes. The AI often skips exception handling, rollback paths, and owners. After the draft, walk through the flow yourself: \\"what if this step fails,\\" \\"who approves,\\" \\"how long does this decision take.\\" Put hidden issues back into the document."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,o.jsx)(r.A,{prompt:i,currentLanguage:"en"})}}}]);